// ─── TRI PARAMS BY DIFFICULTY ──────────────────────────────────
function getTRI(difficulty: string) {
  if (difficulty === 'fácil') return { a: 0.8, b: -1.2, c: 0.15 };
  if (difficulty === 'difícil') return { a: 1.3, b: 1.2, c: 0.25 };
  return { a: 1.0, b: 0.0, c: 0.2 }; // médio
}

