async function main() {
  console.log('🌱 Iniciando seed de questões e simulados...\n');

  // Get microareas
  const microareas = await prisma.microarea.findMany({ include: { elements: true } });
  console.log(`📍 Microareas encontradas: ${microareas.length}`);

  const allQuestions = [...batch1, ...batch2, ...batch3];
  console.log(`📝 Total de questões para seed: ${allQuestions.length}`);

  let seeded = 0;
  let errors = 0;

  for (const q of allQuestions) {
    try {
      const code = TOPIC_TO_CODE[q.topic];
      if (!code) { errors++; continue; }

      const microarea = microareas.find(m => m.code === code);
      if (!microarea) { errors++; continue; }

      const tri = getTRI(q.difficulty);

      await prisma.question.create({
        data: {
          code: q.id,
          type: 'OBJETIVA',
          statement: q.statement,
          correctAnswer: q.correctAnswer,
          explanation: q.explanation,
          difficulty: q.difficulty,
          triA: tri.a,
          triB: tri.b,
          triC: tri.c,
          triCalibrated: false,
          source: 'elaborada',
          microareaId: microarea.id,
          elementId: microarea.elements[0]?.id || null,
          status: 'APROVADA',
          alternatives: {
            create: q.alternatives.map(a => ({ letter: a.letter, text: a.text }))
          }
        }
      });
      seeded++;
    } catch (e: any) {
      errors++;
      if (errors <= 3) console.log(`❌ Erro em ${q.id}: ${e.message?.substring(0, 80)}`);
    }
  }

  console.log(`\n✅ Questões seedadas: ${seeded}`);
  if (errors > 0) console.log(`❌ Erros: ${errors}`);

  // Create Simulados
  const allQ = await prisma.question.findMany({ select: { id: true } });
  console.log(`\n📊 Questões no banco: ${allQ.length}`);

  const simuladoConfigs = [
    { title: 'Simulado Diagnóstico Geral', type: 'DIAGNOSTICO', phase: 1, timeLimit: 120, desc: 'Avaliação diagnóstica com questões de todas as microáreas para identificar pontos fortes e fracos.', qCount: 20 },
    { title: 'Simulado ENADE Completo', type: 'ENADE_SIMULADO', phase: 3, timeLimit: 240, desc: 'Simulação completa do ENADE com 40 questões no formato oficial.', qCount: Math.min(40, allQ.length) },
    { title: 'Simulado Macroarea Desenvolvimento', type: 'MACROAREA', phase: 2, timeLimit: 90, desc: 'Focado em BD, Eng. Software, SO, Redes e Sistemas Distribuídos.', qCount: 20 },
    { title: 'Simulado Fundamentos & Teoria', type: 'MACROAREA', phase: 1, timeLimit: 90, desc: 'Focado em Lógica, Matemática Discreta, Autômatos e Algoritmos.', qCount: 20 },
    { title: 'Simulado Segurança e IA', type: 'MACROAREA', phase: 2, timeLimit: 90, desc: 'Focado em Criptografia, IA, Ciência de Dados, Ética e Legislação.', qCount: 20 },
  ];

  for (const cfg of simuladoConfigs) {
    const shuffled = [...allQ].sort(() => Math.random() - 0.5);
    const selected = shuffled.slice(0, cfg.qCount);
    await prisma.simulado.create({
      data: {
        title: cfg.title,
        description: cfg.desc,
        type: cfg.type,
        phase: cfg.phase,
        timeLimit: cfg.timeLimit,
        questionCount: selected.length,
        active: true,
        configs: { create: selected.map((q, i) => ({ questionId: q.id, order: i })) }
      }
    });
    console.log(`🎯 Criado: ${cfg.title} (${selected.length} questões)`);
  }

  const finalQ = await prisma.question.count();
  const finalS = await prisma.simulado.count();
  console.log(`\n🎉 Final: ${finalQ} questões, ${finalS} simulados`);

  await prisma.$disconnect();
}

main().catch(e => { console.error(e); process.exit(1); });
